import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import api from '../api/axiosConfig';
import toast from 'react-hot-toast';
import { UserPlus, User, Mail, Lock, ShieldCheck } from 'lucide-react';

const RegisterPage = () => {
  const [data, setData] = useState({
    fullName: '',
    email: '',
    password: ''
  });
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleRegister = async (e) => {
    e.preventDefault();

    if (!data.fullName || !data.email || !data.password) {
      toast.error('ALL_FIELDS_REQUIRED');
      return;
    }

    const toastId = toast.loading('INITIALIZING_IDENTITY_NODE...');
    setLoading(true);

    try {
      // Endpoint matches your FastAPI backend structure
      await api.post('/auth/register', data);
      toast.success('IDENTITY_INITIALIZED: ACCESS_GRANTED', { id: toastId });
      navigate('/login');
    } catch (err) {
      toast.error('GATE_REJECTION: REGISTRATION_FAILED', { id: toastId });
    } finally {
      setLoading(false);
    }
  };

  return (
    /* 🎯 THE CENTERING ENGINE: 
       min-h-[85vh] and flex items-center justify-center pull the card 
       away from the top-left corner into the dead center. */
    <div className="min-h-[85vh] w-full flex flex-col items-center justify-center p-6 reveal-data">
      
      {/* 🏛️ The Cyber Card: Small and compact (max-w-md) to match your mockup */}
      <div className="w-full max-w-md cyber-card relative overflow-hidden shadow-2xl">
        
        {/* Ambient Purple Glow matching your Cyber Theme logic */}
        <div className="absolute -top-32 -right-32 w-64 h-64 bg-purple-600/20 blur-[120px]" />

        {/* 📐 Internal Card Padding: p-10 creates the institutional buffer */}
        <div className="relative z-10 p-8 sm:p-10">
          
          {/* Header Section */}
          <div className="text-center mb-10">
            <div className="flex justify-center mb-6 text-purple-400">
              <UserPlus size={42} className="animate-pulse" />
            </div>
            <h1 className="text-3xl font-light tracking-tight text-white mb-2 uppercase">
              Initialize_Node
            </h1>
            <p className="text-white/40 text-[10px] uppercase tracking-[0.25em] font-mono">
              Identity Setup // System_V3.0_Core
            </p>
          </div>

          <form onSubmit={handleRegister} className="space-y-5">
            {/* Identity Field */}
            <div className="space-y-2">
              <label className="flex items-center gap-2 text-[10px] text-purple-400 font-bold uppercase tracking-widest ml-1">
                <User size={12} /> Full_Identity
              </label>
              <input
                type="text"
                className="cyber-input"
                placeholder="Operator Name"
                value={data.fullName}
                onChange={(e) => setData({ ...data, fullName: e.target.value })}
                autoComplete="name"
                required
              />
            </div>

            {/* Email Field */}
            <div className="space-y-2">
              <label className="flex items-center gap-2 text-[10px] text-purple-400 font-bold uppercase tracking-widest ml-1">
                <Mail size={12} /> Registry_Email
              </label>
              <input
                type="email"
                className="cyber-input"
                placeholder="operator@finify.ai"
                value={data.email}
                onChange={(e) => setData({ ...data, email: e.target.value })}
                autoComplete="email"
                required
              />
            </div>

            {/* Security Key Field */}
            <div className="space-y-2">
              <label className="flex items-center gap-2 text-[10px] text-purple-400 font-bold uppercase tracking-widest ml-1">
                <Lock size={12} /> Security_Key
              </label>
              <input
                type="password"
                className="cyber-input"
                placeholder="••••••••"
                value={data.password}
                onChange={(e) => setData({ ...data, password: e.target.value })}
                autoComplete="new-password"
                required
              />
            </div>

            {/* Action Button */}
            <button
              type="submit"
              disabled={loading}
              className={`cyber-btn mt-6 w-full ${loading ? 'opacity-60 cursor-not-allowed' : 'hover:scale-[1.01]'}`}
            >
              {loading ? 'INITIALIZING...' : (
                <span className="flex items-center justify-center gap-2">
                  <ShieldCheck size={16} /> Initialize_New_Identity
                </span>
              )}
            </button>
          </form>

          {/* Footer Navigation */}
          <div className="mt-10 pt-8 border-t border-white/5 text-center">
            <p className="text-[10px] text-white/30 uppercase tracking-[0.25em]">
              Identity already exists?{' '}
              <Link to="/login" className="text-purple-400 hover:underline transition-colors">
                Access_Gate
              </Link>
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default RegisterPage;
